protocols {
    bgp {
        apply-groups GR-BGP;
        path-selection external-router-id;
        advertise-from-main-vpn-tables;
        vpn-apply-export;
        group GR-IBGP-TO-RR-SRV6 {
            local-address $PE_LOCAL_V6;
            family inet {
                unicast {
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                nexthop-resolution { no-resolution; }
            }
            neighbor $RR1_V6 {
                description RR1;
            }
            neighbor $RR2_V6 {
                description RR2;
            }
        }
        source-packet-routing {
            srv6 {
                locator $DEFAULT_SVC_LOC {
                    micro-dt46-sid;
                }
            }
        }
        precision-timers;
        advertise-inactive;
        log-updown;
        bgp-error-tolerance;
        multipath {
            list-nexthop;
        }
        rfc8950-compliant;
    }
}

protocols {
    bgp {
        apply-groups GR-BGP;
        path-selection external-router-id;
        advertise-from-main-vpn-tables;
        vpn-apply-export;

        /* RR<->RR full mesh */
        group GR-IBGP-RRS-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                advertise-default;
                nexthop-resolution { no-resolution; }
            }
            export PS-VPN-SRV6;
            neighbor $RR_PEER_V6 {
                description PEER-RR;
            }
        }

        /* RR clients (PEs / Edges / MSEs) */
        group GR-IBGP-RR-CLIENTS-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                advertise-default;
                nexthop-resolution { no-resolution; }
            }
            cluster $RR_CLUSTER_ID;
            $CLIENT_NEIGHBOR_LIST;
        }

        /* ASBR (BR<->RR) sessions for inter-AS Option C */
        group GR-IBGP-ASBR-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                external-paths 3;
                nexthop-resolution { no-resolution; }
            }
            export PS-VPN-SRV6;
            cluster $RR_CLUSTER_ID;
            $ASBR_NEIGHBOR_LIST;
        }

        precision-timers;
        advertise-inactive;
        log-updown;
        bgp-error-tolerance;
        multipath {
            list-nexthop;
        }
        rfc8950-compliant;
        defaults {
            ebgp {
                no-policy {
                    receive reject-always;
                    advertise reject-always;
                }
            }
        }
    }
}

routing-options {
    transport-class {
        auto-create;
        name TC-128 { color 128; }
        name TC-129 { color 129; }
        name TC-131 { color 131; }
        name TC-132 { color 132; }
        name TC-133 { color 133; }
    }
    flex-algorithm 131 {
        use-transport-class {
            inet3-install;
        }
    }
    flex-algorithm 132 {
        use-transport-class {
            inet3-install;
        }
    }
    flex-algorithm 133 {
        use-transport-class {
            inet3-install;
        }
    }
}

protocols {
    bgp {
        group GR-EBGP-AS$REMOTE_AS-SRV6 {
            multihop {
                ttl 255;
                no-nexthop-change;
            }
            import $EBGP_IMPORT_POLICY;
            family inet-vpn {
                unicast {
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    protection;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                nexthop-resolution { no-resolution; }
            }
            export $EBGP_EXPORT_POLICY_LIST;
            peer-as $REMOTE_AS;
            neighbor $REMOTE_BR_V6_LOOPBACK {
                description $REMOTE_PEER_DESCRIPTION;
                local-address $LOCAL_BR_V6_LOOPBACK;
            }
            advertise-prefix-sid;
            accept-prefix-sid;
        }
    }
}

routing-options {
    flex-algorithm 128 {
        definition {
            metric-type delay-metric;
        }
        use-transport-class {
            inet3-install;
        }
    }
    flex-algorithm 129 {
        definition {
            metric-type te-metric;
        }
        use-transport-class {
            inet3-install;
        }
    }
    source-packet-routing {
        srv6 {
            apply-groups GR-SRV6;
            block $LOC_BLOCK_FA_0 {
                $LOC_BLOCK_PREFIX_0;
                local-micro-sid {
                    maximum-static-sids $LOCAL_USID_LIMIT;
                }
            }
            block $LOC_BLOCK_FA_128 {
                $LOC_BLOCK_PREFIX_128;
                local-micro-sid {
                    maximum-static-sids $LOCAL_USID_LIMIT;
                }
            }
            block $LOC_BLOCK_FA_129 {
                $LOC_BLOCK_PREFIX_129;
                local-micro-sid {
                    maximum-static-sids $LOCAL_USID_LIMIT;
                }
            }
            locator $LOC_FA_0 {
                $LOC_PREFIX_0;
                micro-sid {
                    block-name $LOC_BLOCK_FA_0;
                }
            }
            locator $LOC_FA_128 {
                algorithm 128;
                $LOC_PREFIX_128;
                micro-sid {
                    block-name $LOC_BLOCK_FA_128;
                }
            }
            locator $LOC_FA_129 {
                algorithm 129;
                $LOC_PREFIX_129;
                micro-sid {
                    block-name $LOC_BLOCK_FA_129;
                }
            }
        }
    }
    route-distinguisher-id $RD_ID;
    rib inet.3 {
        protect core;
    }
    resolution {
        preserve-nexthop-hierarchy;
    }
    router-id $ROUTER_ID;
    autonomous-system $LOCAL_AS;
    ipv6-router-id $IPV6_ROUTER_ID;
    protect core;
    forwarding-table {
        srv6-chain-merge;
        export PS-LOAD-BALANCE;
    }
}
protocols {
    isis {
        apply-groups GR-ISIS-IPV6;
        /* Repeat one `interface <ifl>;` per core IFL */
        interface $ISIS_IFL_LIST;
        interface lo0.0 {
            passive;
        }
        source-packet-routing {
            flex-algorithm $FA_LIST;
            no-strict-spf;
            srv6 {
                locator $LOC_FA_0 micro-node-sid;
                locator $LOC_FA_128 micro-node-sid;
                locator $LOC_FA_129 micro-node-sid;
            }
        }
        level 1 disable;
        level 2 {
            purge-originator empty;
            wide-metrics-only;
        }
        backup-spf-options {
            use-post-convergence-lfa maximum-backup-paths 2;
            use-source-packet-routing;
        }
        traffic-engineering {
            l3-unicast-topology;
            tunnel-source-protocol {
                spring-te;
            }
            advertisement always;
        }
        reference-bandwidth $REF_BANDWIDTH;
        max-hello-size $JUMBO_HELLO_SIZE;
        suppress-attached-bit;
        no-external-export {
            protocol bgp;
            protocol ospf;
            protocol static;
        }
        topologies ipv6-unicast;
        overload {
            timeout $OVERLOAD_TIMEOUT;
            advertise-high-metrics;
            internal-prefixes;
            external-prefixes;
        }
        net $ISIS_NET;
    }
}

protocols {
    isis {
        export PS-SRV6-LOC-EXPORT;
    }
    bgp {
        group GR-IBGP-ASBR-SRV6 {
            export PS-SRV6-LOC-EXPORT;
        }
    }
}
policy-options {
    policy-statement PS-SRV6-LOC-EXPORT {
        term TR-SUM-FA-0 {
            from {
                route-filter $SUMMARY_PREFIX_FA_0 exact;
            }
            then accept;
        }
        term TR-SUM-FA-128 {
            from {
                route-filter $SUMMARY_PREFIX_FA_128 exact;
            }
            then accept;
        }
        term TR-SUM-FA-129 {
            from {
                route-filter $SUMMARY_PREFIX_FA_129 exact;
            }
            then accept;
        }
    }
}

protocols {
    isis {
        backup-spf-options {
            use-post-convergence-lfa maximum-backup-paths $MAX_BACKUP_PATHS;
            use-source-packet-routing;
        }
        inactive: spf-options {
            microloop-avoidance {
                post-convergence-path {
                    delay $MLA_DELAY;
                }
            }
            delay 50;
            holddown 2000;
            rapid-runs 5;
        }
    }
}

GR-BGP {
    protocols {
        bgp {
            group <GR-IBGP-*> {
                type internal;
                authentication-algorithm ao;
                authentication-key-chain KC-BGP;
                multipath;
                tcp-mss 4096;
            }
        }
    }
}

GR-CORE-INTF-IPV6 {
    interfaces {
        <*> {
            description ********GR-CORE-INTF-SETTINGS-APPLIED-ADD-DESCRIPTION********;
            traps;
            mtu $JUMBO_L2_MTU;
            hold-time up 2000 down 0;
            unit 0 {
                traps;
                family iso {
                    mtu $JUMBO_L3_MTU;
                }
                family inet6 {
                    mtu $JUMBO_L3_MTU;
                }
            }
        }
        <ae*> {
            aggregated-ether-options {
                bfd-liveness-detection {
                    version automatic;
                    minimum-interval $LACP_BFD_INTERVAL;
                    multiplier $LACP_BFD_MULT;
                    no-adaptation;
                }
                lacp {
                    active;
                    hold-time up 2;
                }
            }
        }
        "<[egx][te]-*>" {
            optics-options {
                alarm low-light-alarm {
                    link-down;
                }
                warning low-light-warning {
                    syslog;
                }
            }
        }
    }
}

GR-ISIS-IPV6 {
    protocols {
        isis {
            interface <*e*> {
                level 1 disable;
                level 2 {
                    srv6-adjacency-segment {
                        unprotected {
                            locator $LOC_FA_0 {
                                micro-adjacency-sid;
                            }
                            locator $LOC_FA_128 {
                                micro-adjacency-sid;
                            }
                            locator $LOC_FA_129 {
                                micro-adjacency-sid;
                            }
                        }
                    }
                    post-convergence-lfa {
                        node-protection cost 16777214;
                    }
                    application-specific {
                        attribute-group LA-FA {
                            advertise-delay-metric;
                            te-metric $TE_METRIC;
                            application {
                                flex-algorithm;
                            }
                        }
                    }
                    inactive: hello-authentication-key-chain KC-ISIS;
                }
                delay-metric $DELAY_METRIC;
                delay-measurement {
                    probe-interval $DELAY_PROBE_INT;
                    probe-count $DELAY_PROBE_COUNT;
                    advertisement {
                        periodic {
                            threshold $DELAY_ADV_THRESH;
                            interval $DELAY_ADV_INTERVAL;
                        }
                    }
                }
                hello-padding strict;
                inactive: max-hello-size $JUMBO_HELLO_SIZE;
                point-to-point;
            }
            interface "<[egx][te]-*>" {
                family inet6 {
                    bfd-liveness-detection {
                        minimum-interval $BFD_MIN_INT;
                        multiplier $BFD_MULT;
                        no-adaptation;
                    }
                }
            }
            interface lo0.0 {
                level 1 disable;
                passive;
            }
        }
    }
}

GR-L3VPN {
    routing-instances {
        <*> {
            instance-type vrf;
            routing-options {
                multipath {
                    vpn-unequal-cost;
                }
            }
            vrf-table-label;
        }
    }
}

GR-SRV6 {
    routing-options {
        source-packet-routing {
            srv6 {
                locator <SL-*> {
                    micro-sid {
                        flavor {
                            psp;
                            usp;
                            usd;
                        }
                    }
                }
            }
        }
    }
}

interfaces {
    $MEMBER_PORT_LIST {
        gigether-options {
            802.3ad ae$AE_NUMBER;
        }
    }
    ae$AE_NUMBER {
        description CORE-TO-$PEER_HOSTNAME;
        flexible-vlan-tagging;
        encapsulation flexible-ethernet-services;
        aggregated-ether-options {
            minimum-links 1;
        }
        unit $UNIT {
            description TO-$PEER_HOSTNAME-VLAN-$VLAN;
            vlan-id $VLAN;
            family iso;
            family inet6 {
                address $LOCAL_V6;
            }
        }
    }
}

interfaces {
    $PHYS_IFL {
        description TO-CPE;
        flexible-vlan-tagging;
        encapsulation flexible-ethernet-services;

        /* Plain L3VPN sub-IFL */
        unit $L3_UNIT {
            vlan-id $L3_VLAN;
            family iso;
            family inet6 {
                address $L3_V6;
            }
        }

        /* EVPN-VPWS attachment circuit */
        unit $VPWS_UNIT {
            description EVPN-VPWS-AC;
            encapsulation vlan-ccc;
            vlan-id $VPWS_VLAN;
            esi {
                $ESI_BYTES;
                $ESI_MODE;
            }
        }

        /* EVPN bridge AC for IRB-stitched L3VPN */
        unit $BRIDGE_UNIT {
            encapsulation vlan-bridge;
            vlan-id $BRIDGE_VLAN;
            family bridge;
        }
    }
}

interfaces {
    $PHYS_IFL {
        vlan-tagging;
        unit $VRF_UNIT {
            vlan-id $VLAN;
            family inet {
                address $PE_CE_V4_LOCAL;
            }
            family inet6 {
                address $PE_CE_V6_LOCAL;
            }
        }
    }
    lo0 {
        unit $VRF_UNIT {
            family inet {
                address $LOOPBACK_V4;
            }
            family inet6 {
                address $LOOPBACK_V6;
            }
        }
    }
}

interfaces {
    $PHYS_IFL {
        flexible-vlan-tagging;
        encapsulation flexible-ethernet-services;
        unit $BD_UNIT {
            encapsulation vlan-bridge;
            vlan-id $VLAN;
            family bridge;
        }
    }
    irb {
        unit $BD_UNIT {
            family inet {
                address $IRB_V4;
            }
            family inet6 {
                address $IRB_V6;
            }
        }
    }
}
bridge-domains {
    BD-$BD_UNIT {
        vlan-id $VLAN;
        routing-interface irb.$BD_UNIT;
    }
}

/*
 * Reference defaults snippet — drop into any block that takes a
 * `bfd-liveness-detection { ... }` stanza (BGP neighbor, IS-IS family,
 * static route, AE bundle, etc.).
 */
bfd-liveness-detection {
    minimum-interval $BFD_MIN_INT;
    multiplier $BFD_MULT;
    no-adaptation;
}

services {
    rpm {
        twamp {
            server {
                authentication-mode none;
                light;
            }
        }
    }
}

policy-options {
    policy-statement PS-LOAD-BALANCE {
        then {
            load-balance per-packet;
        }
    }
}

policy-options {
    policy-statement PS-VPN-SRV6 {
        term TR-L3VPN-SRV6 {
            from {
                rib bgp.l3vpn.0;
                community RT-SRV6;
            }
            then accept;
        }
        term TR-L3VPN-MPLS {
            from rib bgp.l3vpn.0;
            then reject;
        }
    }
    community RT-SRV6 members target:$LOCAL_AS:*;
}

routing-instances {
    $VR_NAME {
        instance-type virtual-router;
        protocols {
            bgp {
                group $PE1_GROUP {
                    local-address $PE1_LOCAL_ADDR;
                    family inet {
                        any;
                    }
                    family inet6 {
                        any;
                    }
                    export EXPORT-TO-EBGP;
                    peer-as $PE1_PEER_AS;
                    local-as $LOCAL_AS;
                    neighbor $PE1_NEIGHBOR;
                }
                /* Second group — omit for single-homed EVPN-T5 CPEs */
                group $PE2_GROUP {
                    local-address $PE2_LOCAL_ADDR;
                    family inet {
                        any;
                    }
                    family inet6 {
                        any;
                    }
                    export EXPORT-TO-EBGP;
                    peer-as $PE1_PEER_AS;
                    local-as $LOCAL_AS;
                    neighbor $PE2_NEIGHBOR;
                }
            }
        }
        interface $ATTACH_IFL_1;
        interface $ATTACH_IFL_2;
    }
}

routing-instances {
    $VPWS_NAME {
        instance-type evpn-vpws;
        protocols {
            evpn {
                interface $AC_IFL {
                    vpws-service-id {
                        local $LOCAL_VPWS_ID;
                        remote $REMOTE_VPWS_ID;
                        source-packet-routing {
                            srv6 locator $LOC;
                        }
                    }
                }
                encapsulation srv6;
            }
        }
        interface $AC_IFL;
        route-distinguisher $RD_SEED:$VPN_ID;
        vrf-target target:$LOCAL_AS:$VPN_ID;
    }
}

routing-instances {
    $VRF_NAME {
        apply-groups GR-L3VPN;
        protocols {
            evpn {
                ip-prefix-routes {
                    advertise direct-nexthop;
                    encapsulation srv6;
                    source-packet-routing {
                        srv6 {
                            locator $LOC {
                                micro-dt46-sid;
                            }
                        }
                    }
                }
            }
        }
        interface $ATTACH_IFL;
        interface $LOOPBACK_IFL;
        route-distinguisher $RD_SEED:$VPN_ID;
        vrf-target target:$RT_AS:$VPN_ID;
    }
}

routing-instances {
    $VRF_NAME {
        apply-groups GR-L3VPN;
        routing-options {
            router-id $VRF_ROUTER_ID;
            protect core;
        }
        protocols {
            bgp {
                group TO-CE {
                    type external;
                    local-address $PE_CE_LOCAL_V4;
                    family inet { any; }
                    family inet6 { any; }
                    peer-as $CE_AS;
                    local-as $LOCAL_AS;
                    as-override;
                    neighbor $PE_CE_NEIGHBOR_V4;
                }
                source-packet-routing {
                    srv6 {
                        locator $LOC {
                            micro-dt46-sid;
                        }
                    }
                }
            }
        }
        interface $ATTACH_IFL;
        interface $LOOPBACK_IFL;
        route-distinguisher $RD_SEED:$VPN_ID;
        vrf-target target:$RT_AS:$VPN_ID;
    }
}

protocols {
    isis {
        interface "<[egx][te]-*>" {
            family inet6 {
                bfd-liveness-detection {
                    minimum-interval $BFD_MIN_INT;
                    multiplier $BFD_MULT;
                    no-adaptation;
                }
            }
        }
    }
}

protocols {
    bgp {
        apply-groups GR-BGP;
        path-selection external-router-id;
        advertise-from-main-vpn-tables;
        vpn-apply-export;
        group GR-IBGP-TO-RR-SRV6 {
            local-address $PE_LOCAL_V6;
            family inet {
                unicast {
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                nexthop-resolution { no-resolution; }
            }
            neighbor $RR1_V6 {
                description RR1;
            }
            neighbor $RR2_V6 {
                description RR2;
            }
        }
        source-packet-routing {
            srv6 {
                locator $DEFAULT_SVC_LOC {
                    micro-dt46-sid;
                }
            }
        }
        precision-timers;
        advertise-inactive;
        log-updown;
        bgp-error-tolerance;
        multipath {
            list-nexthop;
        }
        rfc8950-compliant;
    }
}

protocols {
    bgp {
        apply-groups GR-BGP;
        path-selection external-router-id;
        advertise-from-main-vpn-tables;
        vpn-apply-export;

        /* RR<->RR full mesh */
        group GR-IBGP-RRS-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                advertise-default;
                nexthop-resolution { no-resolution; }
            }
            export PS-VPN-SRV6;
            neighbor $RR_PEER_V6 {
                description PEER-RR;
            }
        }

        /* RR clients (PEs / Edges / MSEs) */
        group GR-IBGP-RR-CLIENTS-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                advertise-default;
                nexthop-resolution { no-resolution; }
            }
            cluster $RR_CLUSTER_ID;
            $CLIENT_NEIGHBOR_LIST;
        }

        /* ASBR (BR<->RR) sessions for inter-AS Option C */
        group GR-IBGP-ASBR-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                external-paths 3;
                nexthop-resolution { no-resolution; }
            }
            export PS-VPN-SRV6;
            cluster $RR_CLUSTER_ID;
            $ASBR_NEIGHBOR_LIST;
        }

        precision-timers;
        advertise-inactive;
        log-updown;
        bgp-error-tolerance;
        multipath {
            list-nexthop;
        }
        rfc8950-compliant;
        defaults {
            ebgp {
                no-policy {
                    receive reject-always;
                    advertise reject-always;
                }
            }
        }
    }
}

routing-options {
    transport-class {
        auto-create;
        name TC-128 { color 128; }
        name TC-129 { color 129; }
        name TC-131 { color 131; }
        name TC-132 { color 132; }
        name TC-133 { color 133; }
    }
    flex-algorithm 131 {
        use-transport-class {
            inet3-install;
        }
    }
    flex-algorithm 132 {
        use-transport-class {
            inet3-install;
        }
    }
    flex-algorithm 133 {
        use-transport-class {
            inet3-install;
        }
    }
}

protocols {
    bgp {
        group GR-EBGP-INTER-AS-OPTION-C {
            type external;
            multihop ttl $EBGP_MULTIHOP_TTL;
            local-address $LOCAL_BR_V6_LOOPBACK;
            family inet {
                unicast {
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            authentication-algorithm ao;
            authentication-key-chain KC-EBGP;
            export PS-INTER-AS-EXPORT;
            import PS-INTER-AS-IMPORT;
            peer-as $REMOTE_AS;
            local-as $LOCAL_AS;
            neighbor $REMOTE_BR_V6_LOOPBACK {
                description PEER-BR;
            }
        }
    }
}

routing-options {
    flex-algorithm 128 {
        definition {
            metric-type delay-metric;
        }
        use-transport-class {
            inet3-install;
        }
    }
    flex-algorithm 129 {
        definition {
            metric-type te-metric;
        }
        use-transport-class {
            inet3-install;
        }
    }
    source-packet-routing {
        srv6 {
            apply-groups GR-SRV6;
            block $LOC_BLOCK_FA_0 {
                $LOC_BLOCK_PREFIX_0;
                local-micro-sid {
                    maximum-static-sids $LOCAL_USID_LIMIT;
                }
            }
            block $LOC_BLOCK_FA_128 {
                $LOC_BLOCK_PREFIX_128;
                local-micro-sid {
                    maximum-static-sids $LOCAL_USID_LIMIT;
                }
            }
            block $LOC_BLOCK_FA_129 {
                $LOC_BLOCK_PREFIX_129;
                local-micro-sid {
                    maximum-static-sids $LOCAL_USID_LIMIT;
                }
            }
            locator $LOC_FA_0 {
                $LOC_PREFIX_0;
                micro-sid {
                    block-name $LOC_BLOCK_FA_0;
                }
            }
            locator $LOC_FA_128 {
                algorithm 128;
                $LOC_PREFIX_128;
                micro-sid {
                    block-name $LOC_BLOCK_FA_128;
                }
            }
            locator $LOC_FA_129 {
                algorithm 129;
                $LOC_PREFIX_129;
                micro-sid {
                    block-name $LOC_BLOCK_FA_129;
                }
            }
        }
    }
    route-distinguisher-id $RD_ID;
    rib inet.3 {
        protect core;
    }
    resolution {
        preserve-nexthop-hierarchy;
    }
    router-id $ROUTER_ID;
    autonomous-system $LOCAL_AS;
    ipv6-router-id $IPV6_ROUTER_ID;
    protect core;
    forwarding-table {
        srv6-chain-merge;
        export PS-LOAD-BALANCE;
    }
}
protocols {
    isis {
        apply-groups GR-ISIS-IPV6;
        /* Repeat one `interface <ifl>;` per core IFL */
        interface $ISIS_IFL_LIST;
        interface lo0.0 {
            passive;
        }
        source-packet-routing {
            flex-algorithm $FA_LIST;
            no-strict-spf;
            srv6 {
                locator $LOC_FA_0 micro-node-sid;
                locator $LOC_FA_128 micro-node-sid;
                locator $LOC_FA_129 micro-node-sid;
            }
        }
        level 1 disable;
        level 2 {
            purge-originator empty;
            wide-metrics-only;
        }
        backup-spf-options {
            use-post-convergence-lfa maximum-backup-paths 2;
            use-source-packet-routing;
        }
        traffic-engineering {
            l3-unicast-topology;
            tunnel-source-protocol {
                spring-te;
            }
            advertisement always;
        }
        reference-bandwidth $REF_BANDWIDTH;
        max-hello-size $JUMBO_HELLO_SIZE;
        suppress-attached-bit;
        no-external-export {
            protocol bgp;
            protocol ospf;
            protocol static;
        }
        topologies ipv6-unicast;
        overload {
            timeout $OVERLOAD_TIMEOUT;
            advertise-high-metrics;
            internal-prefixes;
            external-prefixes;
        }
        net $ISIS_NET;
    }
}

protocols {
    isis {
        export PS-SRV6-LOC-EXPORT;
    }
    bgp {
        group GR-IBGP-ASBR-SRV6 {
            export PS-SRV6-LOC-EXPORT;
        }
    }
}
policy-options {
    policy-statement PS-SRV6-LOC-EXPORT {
        term TR-SUM-FA-0 {
            from {
                route-filter $SUMMARY_PREFIX_FA_0 exact;
            }
            then accept;
        }
        term TR-SUM-FA-128 {
            from {
                route-filter $SUMMARY_PREFIX_FA_128 exact;
            }
            then accept;
        }
        term TR-SUM-FA-129 {
            from {
                route-filter $SUMMARY_PREFIX_FA_129 exact;
            }
            then accept;
        }
    }
}

protocols {
    isis {
        backup-spf-options {
            use-post-convergence-lfa maximum-backup-paths $MAX_BACKUP_PATHS;
            use-source-packet-routing;
        }
        inactive: spf-options {
            microloop-avoidance {
                post-convergence-path {
                    delay $MLA_DELAY;
                }
            }
            delay 50;
            holddown 2000;
            rapid-runs 5;
        }
    }
}
